const generateChartData = ()=>{
    const data = [];
    const today = new Date();
    for(let i = 29; i >= 0; i--){
        const date = new Date(today);
        date.setDate(date.getDate() - i);
        data.push({
            date: date.toLocaleDateString('en-US', {
                month: 'short',
                day: 'numeric'
            }),
            leads: Math.floor(Math.random() * 30) + 10,
            sales: Math.floor(Math.random() * 15) + 5
        });
    }
    return data;
};
